        let mut sm = LDAPDirectoryStateMachine { current_state: LDAPDirectoryState::Draft };
        assert!(sm.can_transition(LDAPDirectoryTransition::Activate));
        let result = sm.transition(LDAPDirectoryTransition::Activate);
        assert!(result.is_ok());
        assert_eq!(sm.current_state(), LDAPDirectoryState::Active);
